module asyn_fifo #(
    parameter DEPTH = 16,
    parameter WIDTH = 8
)(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output reg [WIDTH-1:0] rdata,
    output wfull,
    output rempty
);

// WRITE POINTER
reg [3:0] waddr_bin;
wire [3:0] waddr_gray;
reg [3:0] wptr_buff, wptr;
wire [3:0] wptr_gray;

// READ POINTER
reg [3:0] raddr_bin;
wire [3:0] raddr_gray;
reg [3:0] rptr_buff, rptr_syn;
wire [3:0] rptr_gray;

// Dual-Port RAM
reg wen, ren;
reg [WIDTH-1:0] wdata_dp_ram;
wire [WIDTH-1:0] rdata_dp_ram;

// WRITE POINTER
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn)
        wptr <= 4'd0;
    else if (winc)
        wptr <= wptr + 1;
end

assign waddr_gray = wptr ^ (wptr >> 1);
assign waddr_bin = {
    waddr_gray[3],
    waddr_gray[3] ^ waddr_gray[2],
    waddr_gray[3] ^ waddr_gray[2] ^ waddr_gray[1],
    waddr_gray[3] ^ waddr_gray[2] ^ waddr_gray[1] ^ waddr_gray[0]
};

assign wen = winc & (wptr_gray != {~rptr_gray[3:2], rptr_gray[1:0]});

// READ POINTER
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn)
        rptr <= 4'd0;
    else if (rinc)
        rptr <= rptr + 1;
end

assign raddr_gray = rptr ^ (rptr >> 1);
assign raddr_bin = {
    raddr_gray[3],
    raddr_gray[3] ^ raddr_gray[2],
    raddr_gray[3] ^ raddr_gray[2] ^ raddr_gray[1],
    raddr_gray[3] ^ raddr_gray[2] ^ raddr_gray[1] ^ raddr_gray[0]
};

assign ren = rinc & (rptr_gray != wptr_gray);

// WRITE POINTER BUFFER
always @(posedge rclk or negedge wrstn) begin
    if (!wrstn)
        wptr_buff <= 4'd0;
    else
        wptr_buff <= wptr;
end

// READ POINTER BUFFER
always @(posedge wclk or negedge rrstn) begin
    if (!rrstn)
        rptr_buff <= 4'd0;
    else
        rptr_buff <= rptr;
end

// SYNC
always @(posedge wclk or negedge rrstn) begin
    if (!rrstn)
        rptr_syn <= 4'd0;
    else
        rptr_syn <= rptr_buff;
end

assign wfull = (wptr_gray == {~rptr_syn[3:2], rptr_syn[1:0]});
assign rempty = (wptr_gray == rptr_gray);

// Dual-Port RAM
always @(posedge wclk) begin
    if (wen)
        wdata_dp_ram <= wdata;
end

assign rdata_dp_ram = wdata_dp_ram;

always @(posedge rclk) begin
    if (ren)
        rdata <= rdata_dp_ram;
end
endmodule
